import React, { useState, useEffect } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { Mail, CheckCircle, XCircle, RefreshCw } from 'lucide-react';

const EmailVerification = () => {
  const [searchParams] = useSearchParams();
  const [status, setStatus] = useState('loading'); // loading, success, error
  const [message, setMessage] = useState('');
  const { verifyEmail } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    const token = searchParams.get('token');

    if (!token) {
      setStatus('error');
      setMessage('No verification token provided');
      return;
    }

    const verify = async () => {
      try {
        const result = await verifyEmail(token);
        if (result.success) {
          setStatus('success');
          setMessage('Your email has been successfully verified! You can now login to your account.');
        } else {
          setStatus('error');
          setMessage(result.message || 'Email verification failed');
        }
      } catch (error) {
        setStatus('error');
        setMessage('An error occurred during email verification');
      }
    };

    verify();
  }, [searchParams, verifyEmail]);

  const handleLogin = () => {
    navigate('/login');
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-md w-full">
        <div className="text-center">
          {status === 'loading' && (
            <div className="mx-auto h-16 w-16 flex items-center justify-center rounded-full bg-primary-100">
              <RefreshCw className="h-8 w-8 text-primary-600 animate-spin" />
            </div>
          )}

          {status === 'success' && (
            <div className="mx-auto h-16 w-16 flex items-center justify-center rounded-full bg-success-100">
              <CheckCircle className="h-8 w-8 text-success-600" />
            </div>
          )}

          {status === 'error' && (
            <div className="mx-auto h-16 w-16 flex items-center justify-center rounded-full bg-error-100">
              <XCircle className="h-8 w-8 text-error-600" />
            </div>
          )}

          <h2 className="mt-6 text-3xl font-extrabold text-gray-900">
            {status === 'loading' && 'Verifying Your Email...'}
            {status === 'success' && 'Email Verified!'}
            {status === 'error' && 'Verification Failed'}
          </h2>

          <div className="mt-4">
            {status === 'loading' && (
              <p className="text-sm text-gray-600">
                Please wait while we verify your email address...
              </p>
            )}

            {status === 'success' && (
              <div className="space-y-4">
                <p className="text-sm text-gray-600">
                  {message}
                </p>
                <button
                  onClick={handleLogin}
                  className="btn btn-primary"
                >
                  Go to Login
                </button>
              </div>
            )}

            {status === 'error' && (
              <div className="space-y-4">
                <p className="text-sm text-error-600">
                  {message}
                </p>
                <div className="space-y-2">
                  <p className="text-xs text-gray-500">
                    Possible reasons:
                  </p>
                  <ul className="text-xs text-gray-500 text-left space-y-1">
                    <li>• The verification link has expired</li>
                    <li>• The verification link has already been used</li>
                    <li>• The verification link is invalid</li>
                  </ul>
                </div>
                <div className="flex space-x-3 justify-center">
                  <button
                    onClick={() => navigate('/login')}
                    className="btn btn-secondary"
                  >
                    Back to Login
                  </button>
                  <button
                    onClick={() => navigate('/register')}
                    className="btn btn-primary"
                  >
                    Register Again
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="mt-8">
          <div className="mx-auto h-12 w-12 flex items-center justify-center rounded-full bg-gray-100">
            <Mail className="h-6 w-6 text-gray-600" />
          </div>
          <p className="mt-2 text-center text-xs text-gray-500">
            If you continue to experience issues, please contact the system administrator.
          </p>
        </div>
      </div>
    </div>
  );
};

export default EmailVerification;
